const computeOEE=(a,p,q)=>+(a/100*p/100*q/100*100).toFixed(2);

async function fetchData(){
  const res = await fetch('/oee/data');
  return res.json();
}

const elA=document.getElementById('kpiAvailability'),
      elP=document.getElementById('kpiPerformance'),
      elQ=document.getElementById('kpiQuality'),
      elO=document.getElementById('kpiOEE');
const tbody=document.querySelector('#machinesTable tbody');
let oeeTrendChart, lossesChart;

function createCharts(){
  const ctx1=document.getElementById('oeeTrendChart').getContext('2d');
  const ctx2=document.getElementById('lossesChart').getContext('2d');

  oeeTrendChart=new Chart(ctx1,{
    type:'line',
    data:{
      labels:['-5h','-4h','-3h','-2h','-1h','Now'],
      datasets:[{label:'OEE %',data:[],tension:0.3,borderWidth:2,fill:true}]
    },
    options:{
      scales:{y:{beginAtZero:true,max:100}},
      plugins:{legend:{display:false}}
    }
  });

  lossesChart=new Chart(ctx2,{
    type:'bar',
    data:{
      labels:[],
      datasets:[{label:'Loss %',data:[],borderRadius:6}]
    },
    options:{
      indexAxis:'y',
      scales:{x:{beginAtZero:true,max:100}},
      plugins:{legend:{display:false}}
    }
  });
}

function renderTable(data){
  tbody.innerHTML='';
  data.forEach(m=>{
    const tr=document.createElement('tr');
    tr.innerHTML=\`
      <td>\${m.Mesin}</td>
      <td>\${m.Availability}%</td>
      <td>\${m.Performance}%</td>
      <td>\${m.Quality}%</td>
      <td><strong>\${m.OEE}%</strong></td>
      <td>\${m.Status}</td>\`;
    tbody.appendChild(tr);
  });
}

async function init(){
  const all = await fetchData();
  if(!all || !all.machines) return;

  renderTable(all.machines);
  const avg=all.avg;
  elA.textContent=avg.availability+'%';
  elP.textContent=avg.performance+'%';
  elQ.textContent=avg.quality+'%';
  elO.textContent=avg.oee+'%';

  oeeTrendChart.data.datasets[0].data=all.trend;
  oeeTrendChart.update();

  lossesChart.data.labels=all.loss.labels;
  lossesChart.data.datasets[0].data=all.loss.values;
  lossesChart.update();
}

createCharts();
init();

