  const inputBtn = document.getElementById("inputBtn");

  inputBtn.addEventListener("click", () => {
    // Navigasi halus ke halaman input
    inputBtn.textContent = "Membuka...";
    inputBtn.disabled = true;
    inputBtn.style.opacity = "0.7";

    setTimeout(() => {
      window.location.href = "/oee/input";
    }, 500);
  });
});

`);
